parameters.jsCode:
const input = (
  $json.chatInput ||
  $json.message ||
  $json.text ||
  ""
).trim().toLowerCase();

const state = $json.current_state || "";
let nextScreen = "";
let just_entered = false;

/* =========================
   WELCOME
========================= */

if (["hi", "hello", "start", ""].includes(input)) {
  nextScreen = "ST001";
}

/* =========================
   LANGUAGE
========================= */

else if (state === "ST001") {

  if (
    ["0", "english", "en"].includes(input)
  ) {
    nextScreen = "ST002";
    $json.language = "en";
  }

  else if (
    ["1", "marathi", "mr"].includes(input)
  ) {
    nextScreen = "ST002";
    $json.language = "mr";
  }
}

/* =========================
   MAIN MENU
========================= */

else if (state === "ST002") {

  switch (input) {

    case "0":
    case "building_permission":
      nextScreen = "ST101";
      just_entered = true;
      break;

    case "1":
    case "zone_certificate":
      nextScreen = "ST201";
      just_entered = true;
      break;

    case "2":
    case "part_plan":
      nextScreen = "ST301";
      just_entered = true;
      break;

    case "3":
    case "gunthewari":
      nextScreen = "ST401";
      just_entered = true;
      break;

    case "4":
    case "ai_assistant":
      nextScreen = "ST501";
      just_entered = true;
      break;
  }
}

/* =========================
   BUILDING MENU
========================= */

else if (state === "ST101") {

  switch (input) {

    case "0":
    case "layout_documents":
      nextScreen = "ST102";
      break;

    case "1":
    case "building_documents":
      nextScreen = "ST103";
      break;

    case "2":
    case "occupancy_documents":
      nextScreen = "ST104";
      break;

    case "3":
    case "open_bpms":
      nextScreen = "ST105";
      break;

    case "4":
    case "back":
      nextScreen = "ST002";
      break;
  }
}

/* =========================
   LAYOUT DOCS
========================= */

else if (state === "ST102") {

  switch (input) {

    case "0":
    case "download_pdf":
      nextScreen = "DOWNLOAD_LAYOUT";
      break;

    case "1":
    case "bpms":
      nextScreen = "ST105";
      break;

    case "2":
    case "back":
      nextScreen = "ST101";
      break;
  }
}

/* =========================
   BUILDING DOCS
========================= */

else if (state === "ST103") {

  switch (input) {

    case "0":
    case "download_pdf":
      nextScreen = "DOWNLOAD_BUILDING_PERMISSION";
      break;

    case "1":
    case "bpms":
      nextScreen = "ST105";
      break;

    case "2":
    case "back":
      nextScreen = "ST101";
      break;
  }
}

/* =========================
   OCCUPANCY
========================= */

else if (state === "ST104") {

  switch (input) {

    case "0":
    case "download_pdf":
      nextScreen = "DOWNLOAD_OCCUPANCY";
      break;

    case "1":
    case "bpms":
      nextScreen = "ST105";
      break;

    case "2":
    case "back":
      nextScreen = "ST101";
      break;
  }
}

/* =========================
   BPMS
========================= */

else if (state === "ST105") {

  switch (input) {

    case "0":
    case "open":
    case "open_portal":
      nextScreen = "OPEN_BPMS";
      break;

    case "1":
    case "back":
      nextScreen = "ST101";
      break;
  }
}

/* =========================
   ZONE CERTIFICATE
========================= */

else if (state === "ST201") {

  switch (input) {

    case "0":
    case "apply_here":
      nextScreen = "ST202";
      break;

    case "1":
    case "aaple_sarkar":
      nextScreen = "ST203";
      break;

    case "2":
    case "back":
      nextScreen = "ST002";
      break;
  }
}

else if (state === "ST202") {

  switch (input) {

    case "0":
    case "register":
      nextScreen = "ST206";
      break;

    case "1":
    case "login":
      nextScreen = "ST207";
      break;

    case "2":
    case "track":
      nextScreen = "ST208";
      break;

    case "3":
    case "back":
      nextScreen = "ST201";
      break;
  }
}

else if (state === "ST203") {

  switch (input) {

    case "0":
    case "open":
    case "open_portal":
      nextScreen = "OPEN_AAPLE_SARKAR";
      break;

    case "1":
    case "back":
      nextScreen = "ST201";
      break;
  }
}

else if (state === "ST206") {

  switch (input) {

    case "0":
    case "open_registration":
      nextScreen = "REGISTER_PORTAL";
      break;

    case "1":
    case "back":
      nextScreen = "ST202";
      break;
  }
}

else if (state === "ST207") {

  switch (input) {

    case "0":
    case "open_login":
      nextScreen = "LOGIN_PORTAL";
      break;

    case "1":
    case "back":
      nextScreen = "ST202";
      break;
  }
}

else if (state === "ST208") {

  switch (input) {

    case "0":
    case "track_application":
      nextScreen = "TRACK_APPLICATION";
      break;

    case "1":
    case "back":
      nextScreen = "ST202";
      break;
  }
}

/* =========================
   PART PLAN
========================= */

else if (state === "ST301") {

  switch (input) {

    case "0":
    case "apply_here":
      nextScreen = "ST302";
      break;

    case "1":
    case "aaple_sarkar":
      nextScreen = "ST303";
      break;

    case "2":
    case "back":
      nextScreen = "ST002";
      break;
  }
}

else if (state === "ST302") {

  switch (input) {

    case "0":
    case "register":
      nextScreen = "ST306";
      break;

    case "1":
    case "login":
      nextScreen = "ST307";
      break;

    case "2":
    case "track":
      nextScreen = "ST308";
      break;

    case "3":
    case "back":
      nextScreen = "ST301";
      break;
  }
}

else if (state === "ST303") {

  switch (input) {

    case "0":
    case "open":
    case "open_portal":
      nextScreen = "OPEN_AAPLE_SARKAR_PART";
      break;

    case "1":
    case "back":
      nextScreen = "ST301";
      break;
  }
}

else if (state === "ST306") {

  switch (input) {

    case "0":
    case "open_registration":
      nextScreen = "REGISTER_PART_PLAN";
      break;

    case "1":
    case "back":
      nextScreen = "ST302";
      break;
  }
}

else if (state === "ST307") {

  switch (input) {

    case "0":
    case "open_login":
      nextScreen = "LOGIN_PART_PLAN";
      break;

    case "1":
    case "back":
      nextScreen = "ST302";
      break;
  }
}

else if (state === "ST308") {

  switch (input) {

    case "0":
    case "track_application":
      nextScreen = "TRACK_PART_PLAN";
      break;

    case "1":
    case "back":
      nextScreen = "ST302";
      break;
  }
}

/* =========================
   GUNTHEWARI
========================= */

else if (state === "ST401") {

  switch (input) {

    case "0":
    case "open_portal":
      nextScreen = "ST402";
      break;

    case "1":
    case "back":
      nextScreen = "ST002";
      break;
  }
}

else if (state === "ST402") {

  switch (input) {

    case "0":
    case "open_gunthewari":
      nextScreen = "OPEN_GUNTHEVARI_PORTAL";
      break;

    case "1":
    case "back":
      nextScreen = "ST401";
      break;
  }
}

/* =========================
   AI ASSISTANT
========================= */

else if (state === "ST501") {

  if (
    ["back", "menu", "exit"].includes(input)
  ) {
    nextScreen = "ST002";
  } else {
    nextScreen = "AI_CHAT";
  }
}

/* =========================
   FALLBACK
========================= */

if (!nextScreen) {
  nextScreen = state || "ST001";
}

return [{
  json: {
    ...$json,
    nextScreen,
    just_entered
  }
}];

